import React, { useState } from 'react';
import axios from 'axios';

const CROPS = ['TOMATO', 'WHEAT', 'RICE', 'MAIZE'];
const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000';

/**
 * Upload form component — CSV file upload + crop selection.
 */
function UploadForm({ setResults, setLoading, setError }) {
  const [file, setFile] = useState(null);
  const [crop, setCrop] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setResults([]);

    if (!file) {
      setError('Please select a CSV file.');
      return;
    }
    if (!crop) {
      setError('Please select a crop type.');
      return;
    }

    const formData = new FormData();
    formData.append('file', file);
    formData.append('crop', crop);

    setLoading(true);
    try {
      const response = await axios.post(`${API_URL}/analyze-soil`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      setResults(response.data.results);
      // Also log to console as required
      console.log('AgriPulse Analysis Results:', JSON.stringify(response.data.results, null, 2));
    } catch (err) {
      const detail = err.response?.data?.detail || err.message;
      setError(`Analysis failed: ${detail}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="upload-card">
      <h2>📤 Upload Soil Data</h2>
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label htmlFor="csv-file">Soil CSV File</label>
          <input
            id="csv-file"
            type="file"
            accept=".csv"
            onChange={(e) => setFile(e.target.files[0])}
          />
        </div>
        <div className="form-group">
          <label htmlFor="crop-select">Target Crop</label>
          <select
            id="crop-select"
            value={crop}
            onChange={(e) => setCrop(e.target.value)}
          >
            <option value="">— Select a crop —</option>
            {CROPS.map((c) => (
              <option key={c} value={c}>{c}</option>
            ))}
          </select>
        </div>
        <button type="submit" className="btn-analyze">
          Analyze Soil
        </button>
      </form>
    </div>
  );
}

export default UploadForm;
